import streamlit as stimport pandas as pdimport plotly.express as pximport plotly.graph_objects as gofrom datetime import datetime# --- SAYFA AYARLARI ---st.set_page_config(page_title="Focus AI | Master Coach", layout="wide", initial_sidebar_state="expanded")# --- SİSTEM HAFIZASI (VERİTABANI SİMÜLASYONU) ---# Gerçek uygulamada bunlar SQL veya CSV'ye bağlanabilir.for key in ['ogrenciler', 'denemeler', 'kitaplar', 'videolar', 'ajanda', 'soru_havuzu']:    if key not in st.session_state:        if key == 'ogrenciler':            st.session_state[key] = pd.DataFrame(columns=["Ad Soyad", "Veli Adı", "Veli Tel", "Seviye"])        else:            st.session_state[key] = pd.DataFrame()# --- YÖNETİM PANELİ (SIDEBAR) ---st.sidebar.title("🎯 Focus AI v2.0")st.sidebar.image("https://img.icons8.com/fluency/96/brain--v1.png", width=80)role = st.sidebar.radio("Sistem Rolü Seçin:", ["👨‍🏫 KOÇ / ÖĞRETMEN", "🎓 ÖĞRENCİ PANELİ"])# ==========================================# 👨‍🏫 MODÜL 1: KOÇ / ÖĞRETMEN YÖNETİMİ# ==========================================if role == "👨‍🏫 KOÇ / ÖĞRETMEN":    st.title("🚀 Focus AI: Operasyon ve Analiz Merkezi")        tabs = st.tabs(["📊 Deneme & Radar", "📚 Kitap & Video Takibi", "📅 Ajanda & Program", "👤 Kayıt & Rehber", "✂️ Test Hazırlama"])    # --- TAB 1: DENEME ANALİZİ (RADAR & KARŞILAŞTIRMA) ---    with tabs[0]:        st.subheader("🕸️ Akademik Başarı Radarı")        col_r1, col_r2 = st.columns([1, 2])                with col_r1:            st.write("### Veri Girişi")            with st.form("deneme_form"):                o_ad = st.selectbox("Öğrenci", st.session_state.ogrenciler["Ad Soyad"] if not st.session_state.ogrenciler.empty else ["Kayıt Yok"])                d_ad = st.text_input("Sınav Adı (Örn: TYT-1)")                c1, c2 = st.columns(2)                mat = c1.number_input("Matematik Net", 0.0, 40.0)                tur = c2.number_input("Türkçe Net", 0.0, 40.0)                fen = c1.number_input("Fen Net", 0.0, 20.0)                sos = c2.number_input("Sosyal Net", 0.0, 20.0)                if st.form_submit_button("Sınavı Kaydet"):                    yeni_d = pd.DataFrame([[o_ad, d_ad, mat, tur, fen, sos]], columns=["Öğrenci", "Sınav", "Matematik", "Türkçe", "Fen", "Sosyal"])                    st.session_state.denemeler = pd.concat([st.session_state.denemeler, yeni_d], ignore_index=True)                    st.success("Deneme başarıyla işlendi!")        with col_r2:            if not st.session_state.denemeler.empty:                st.write("### Gelişim Analizi")                categories = ['Matematik', 'Türkçe', 'Fen', 'Sosyal']                fig = go.Figure()                # Son sınav verisini çek                last_val = st.session_state.denemeler.iloc[-1][categories].values                fig.add_trace(go.Scatterpolar(r=last_val, theta=categories, fill='toself', name='Son Sınav'))                fig.update_layout(polar=dict(radialaxis=dict(visible=True, range=[0, 40])), showlegend=True)                st.plotly_chart(fig, use_container_width=True)    # --- TAB 2: KİTAP VE VİDEO TAKİBİ ---    with tabs[1]:        st.subheader("📖 Müfredat ve Kaynak Yönetimi")        c_k1, c_k2 = st.columns(2)        with c_k1:            st.write("#### 📗 Kitap Takibi")            st.info("Öğrencinin bitirdiği test yüzdelerini buradan izleyin.")            # Simülasyon tablosu            st.table(pd.DataFrame({"Öğrenci": ["Arda"], "Kitap": ["3D Mat"], "İlerleme": ["%65"]}))                    with c_k2:            st.write("#### 📺 YouTube Video Takibi")            v_link = st.text_input("YouTube Playlist Linki Ata")            if st.button("Playlisti Öğrenciye Gönder"):                st.toast("Video ödevi başarıyla iletildi!")    # --- TAB 3: AJANDA VE PROGRAMLAMA ---    with tabs[2]:        st.subheader("📅 Haftalık Çalışma Ajandası")        st.write("Sürükle-bırak mantığıyla öğrenciye özel görevler tanımlayın.")        with st.expander("➕ Yeni Görev Tanımla"):            col_a1, col_a2 = st.columns(2)            col_a1.date_input("Görev Tarihi")            col_a1.text_area("Görev Notu (Örn: Paragraf 5 test)")            col_a2.selectbox("Öncelik", ["Yüksek", "Orta", "Düşük"])            st.button("Ajandaya İşle")    # --- TAB 4: REHBER VE WHATSAPP ---    with tabs[3]:        st.subheader("👤 Öğrenci & Veli Veritabanı")        with st.form("kayit"):            c_v1, c_v2 = st.columns(2)            ad = c_v1.text_input("Ad Soyad")            v_ad = c_v2.text_input("Veli Adı")            v_tel = c_v1.text_input("Veli Tel (Örn: 905xx)")            if st.form_submit_button("Kayıt Et"):                yeni_o = pd.DataFrame([[ad, v_ad, v_tel, "12. Sınıf"]], columns=st.session_state.ogrenciler.columns)                st.session_state.ogrenciler = pd.concat([st.session_state.ogrenciler, yeni_o], ignore_index=True)        st.dataframe(st.session_state.ogrenciler, use_container_width=True)                if not st.session_state.ogrenciler.empty:            st.write("### 📩 Hızlı Rapor Gönder")            sel_o = st.selectbox("Öğrenci Seç", st.session_state.ogrenciler["Ad Soyad"])            msg = f"Sayın Velimiz, öğrencimiz {sel_o} bugün Focus AI sisteminde %85 başarı göstermiştir."            wa_link = f"https://wa.me/{st.session_state.ogrenciler.iloc[0]['Veli Tel']}?text={msg.replace(' ', '%20')}"            st.link_button("🟢 WhatsApp'tan Gönder", wa_link)    # --- TAB 5: PDF TEST HAZIRLAMA ---    with tabs[4]:        st.subheader("✂️ PDF Soru Kırpma ve Dijital Test")        pdf_file = st.file_uploader("Soru Bankası PDF Yükle", type="pdf")        if pdf_file:            st.image("https://img.icons8.com/clouds/100/pdf.png", width=100)            st.warning("Seçtiğiniz alanlar otomatik olarak 'Öğrenci Paneli'ne test olarak düşecektir.")            st.button("Kırpılan Soruyu Havuza Ekle")# ==========================================# 🎓 MODÜL 2: ÖĞRENCİ PANELİ# ==========================================else:    st.title("🎓 Focus AI: Öğrenci Portalı")    st.info("Merhaba! Bugün hedeflerine bir adım daha yaklaştın. 🚀")        st.write("---")    c_o1, c_o2 = st.columns([2, 1])        with c_o1:        st.subheader("📝 Günlük Soru ve Başarı Girişi")        with st.form("soru_takibi"):            ders_s = st.selectbox("Ders", ["Matematik", "Türkçe", "Fen"])            c_s1, c_s2, c_s3 = st.columns(3)            d = c_s1.number_input("Doğru", 0)            y = c_s2.number_input("Yanlış", 0)            b = c_s3.number_input("Boş", 0)            if st.form_submit_button("Sisteme İşle"):                st.success("Verilerin başarıyla koçuna iletildi!")    with c_o2:        st.subheader("📺 Atanan Videolar")        st.video("https://www.youtube.com/watch?v=dQw4w9WgXcQ") # Örnek Video        st.button("İzledim")    st.write("---")    st.subheader("📚 Kitap Bitirme Durumum")    st.write("3D Matematik Soru Bankası")    st.progress(0.65)    st.caption("%65 Tamamlandı")